import{V as s}from"./index-CcRFyznd.js";const m=s("cart",{state:()=>({items:[],discount:0,taxRate:0}),getters:{itemCount:t=>t.items.reduce((e,i)=>e+i.quantity,0),subtotal:t=>t.items.reduce((e,i)=>e+i.price*i.quantity,0),tax:t=>t.items.reduce((i,a)=>i+a.price*a.quantity,0)*t.taxRate/100,total(){return Math.max(0,this.subtotal+this.tax-this.discount)}},actions:{addItem(t,e=1){const i=this.items.find(a=>a.id===t.id);i?i.quantity+=e:this.items.push({id:t.id,name:t.name,price:parseFloat(t.price),quantity:e,maxQuantity:t.quantity,image:t.image})},updateQuantity(t,e){const i=this.items.find(a=>a.id===t);i&&(i.quantity=Math.max(1,Math.min(e,i.maxQuantity)))},removeItem(t){const e=this.items.findIndex(i=>i.id===t);e>-1&&this.items.splice(e,1)},setDiscount(t){this.discount=Math.max(0,t)},setTaxRate(t){this.taxRate=Math.max(0,t)},clear(){this.items=[],this.discount=0},getItemsForApi(){return this.items.map(t=>({product_id:t.id,quantity:t.quantity}))}}});export{m as u};
